function solve(s) {
    const n = s.length;

    // We need to find the minimum index i such that s[i] == s[n - i - 1].
    // We should iterate i starting from 0 up to the middle of the string (floor(n/2)).
    // Since we are looking for the *smallest* i, a linear search from i=0 is appropriate.

    // The loop should run as long as i is less than n - i - 1 (i.e., i < n/2) 
    // or equal to it (if n is odd, the middle element case).

    // The problem statement implies checking all relevant indices i.
    // The indices i and n - i - 1 form a pair. We only need to check i up to the midpoint.

    // If n is odd, the middle index is floor(n/2). When i = floor(n/2), i == n - i - 1.
    // If n is even, the last pair check is when i = n/2 - 1.

    // Let's iterate i from 0 up to n-1, but since the condition s[i] == s[n - i - 1]
    // is symmetric, we only need to check i such that i <= n - i - 1, which means 2i <= n - 1, or i <= (n - 1) / 2.
    // In integer math, this is i <= floor((n - 1) / 2).

    const limit = Math.floor((n - 1) / 2);

    for (let i = 0; i <= limit; i++) {
        const j = n - 1 - i; // j is the corresponding index

        if (s[i] === s[j]) {
            // Found the smallest such i
            return i;
        }
    }

    // If no such index is found
    return -1;
}

